function readTsvRows(path) {
  const lines = readFileSync(path, 'utf8').trimEnd().split('\n');
  const header = lines[0];
  const body = lines.slice(1);
  return { header, body };
}

const { header, body } = readTsvRows(TSV_PATH);
const existingIds = new Set(body.map((line) => line.split('\t')[1]));
const nextBody = [...body];

for (const row of rows) {
  if (existingIds.has(row[0])) continue;
  const rank = nextBody.length + 1;
  nextBody.push([rank, ...row].join('\t'));
}

const details = JSON.parse(readFileSync(DETAILS_PATH, 'utf8'));
for (const row of detailRows) {
  const [id, year, combatants, outcome, war, location, series, gloss] = row;
  details[id] = {
    year,
    combatants,
    outcome,
    war,
    location,
    continent: undefined,
    epoch: undefined,
    series: {
      key: series[0],
      label: series[1],
      order: series[2],
    },
    gloss,
  };
  delete details[id].continent;
  delete details[id].epoch;
}

writeFileSync(TSV_PATH, `${header}\n${nextBody.join('\n')}\n`);
writeFileSync(DETAILS_PATH, `${JSON.stringify(details, null, 2)}\n`);

console.log(`Candidate rows: ${nextBody.length}`);
console.log(`Detail rows: ${Object.keys(details).length}`);
